from __future__ import annotations


def plan_batches(
    dependencies: dict[str, list[str]],
    *,
    completed: set[str] | None = None,
) -> list[list[str]]:
    done = set(completed or set())
    tasks = set(dependencies)
    for blockers in dependencies.values():
        tasks.update(blockers)

    remaining = {
        task: set(dependencies.get(task, [])) - done
        for task in tasks
        if task not in done
    }
    batches: list[list[str]] = []

    while remaining:
        ready = sorted(task for task, blockers in remaining.items() if not blockers)
        if not ready:
            raise ValueError("dependency graph contains a cycle")

        batches.append(ready)
        newly_completed = set(ready)
        remaining = {
            task: blockers - newly_completed
            for task, blockers in remaining.items()
            if task not in newly_completed
        }

    return batches

